create extension if not exists "pgcrypto";
create extension if not exists btree_gist;
create type public.app_role as enum ('customer','staff','admin','super_admin');
create type public.booking_status as enum ('draft','pending_payment','confirmed','cancelled','completed','refunded');
create table public.profiles (id uuid primary key references auth.users on delete cascade, full_name text, phone text, role app_role not null default 'customer', avatar_url text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.cities (id uuid primary key default gen_random_uuid(), name text not null unique, slug text not null unique, is_active boolean not null default true, created_at timestamptz not null default now());
create table public.branches (id uuid primary key default gen_random_uuid(), city_id uuid not null references public.cities, name text not null, address text, latitude numeric, longitude numeric, is_active boolean not null default true, created_at timestamptz not null default now());
create table public.experiences (id uuid primary key default gen_random_uuid(), name text not null unique, slug text not null unique, description text, cover_url text, is_active boolean not null default true, created_at timestamptz not null default now());
create table public.halls (id uuid primary key default gen_random_uuid(), branch_id uuid not null references public.branches, name text not null, capacity_min int not null check(capacity_min>0), capacity_max int not null check(capacity_max>=capacity_min), size_sqft int, amenities jsonb not null default '[]', base_price numeric(12,2) not null check(base_price>=0), is_featured boolean not null default false, maintenance_until timestamptz, deleted_at timestamptz, created_at timestamptz not null default now());
create table public.hall_media (id uuid primary key default gen_random_uuid(), hall_id uuid not null references public.halls on delete cascade, url text not null, media_type text not null check(media_type in ('image','video','360')), sort_order int not null default 0, created_at timestamptz not null default now());
create table public.packages (id uuid primary key default gen_random_uuid(), experience_id uuid references public.experiences, name text not null, tier text, price numeric(12,2) not null, description text, is_featured boolean not null default false, is_active boolean not null default true, created_at timestamptz not null default now());
create table public.package_items (id uuid primary key default gen_random_uuid(), package_id uuid not null references public.packages on delete cascade, name text not null, quantity int not null default 1, created_at timestamptz not null default now());
create table public.addons (id uuid primary key default gen_random_uuid(), name text not null, price numeric(12,2) not null, is_active boolean not null default true, created_at timestamptz not null default now());
create table public.bookings (id uuid primary key default gen_random_uuid(), booking_code text not null unique default ('HOS-'||upper(substr(replace(gen_random_uuid()::text,'-',''),1,8))), customer_id uuid not null references public.profiles, branch_id uuid not null references public.branches, hall_id uuid not null references public.halls, experience_id uuid references public.experiences, package_id uuid references public.packages, event_date date not null, slot_start timestamptz not null, slot_end timestamptz not null, guest_count int not null default 2, occasion_name text, honoree_name text, special_request text, status booking_status not null default 'draft', subtotal numeric(12,2) not null default 0, tax numeric(12,2) not null default 0, total numeric(12,2) not null default 0, slot_lock_expires_at timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), check(slot_end>slot_start));
create table public.booking_items (id uuid primary key default gen_random_uuid(), booking_id uuid not null references public.bookings on delete cascade, addon_id uuid references public.addons, item_name text not null, quantity int not null default 1 check(quantity>0), unit_price numeric(12,2) not null default 0);
create table public.payments (id uuid primary key default gen_random_uuid(), booking_id uuid not null references public.bookings, provider text not null default 'razorpay', provider_payment_id text unique, amount numeric(12,2) not null, currency text not null default 'INR', status text not null default 'created', created_at timestamptz not null default now());
create table public.payment_logs (id uuid primary key default gen_random_uuid(), payment_id uuid not null references public.payments on delete cascade, payload jsonb not null default '{}', created_at timestamptz not null default now());
create table public.reviews (id uuid primary key default gen_random_uuid(), booking_id uuid unique references public.bookings, customer_id uuid not null references public.profiles, rating int not null check(rating between 1 and 5), body text, is_published boolean not null default false, created_at timestamptz not null default now());
create table public.gallery (id uuid primary key default gen_random_uuid(), url text not null, alt_text text, category text, is_featured boolean not null default false, created_at timestamptz not null default now());
create table public.notifications (id uuid primary key default gen_random_uuid(), user_id uuid not null references public.profiles on delete cascade, title text not null, body text, read_at timestamptz, created_at timestamptz not null default now());
create table public.coupons (id uuid primary key default gen_random_uuid(), code text unique not null, percentage numeric(5,2), amount numeric(12,2), starts_at timestamptz, ends_at timestamptz, usage_limit int, active boolean not null default true);
create table public.gift_cards (id uuid primary key default gen_random_uuid(), code text unique not null, balance numeric(12,2) not null check(balance>=0), expires_at timestamptz, created_at timestamptz not null default now());
create table public.referrals (id uuid primary key default gen_random_uuid(), referrer_id uuid not null references public.profiles, referee_id uuid unique references public.profiles, code text not null, rewarded_at timestamptz);
create table public.reward_points (id uuid primary key default gen_random_uuid(), profile_id uuid not null references public.profiles, points int not null, reason text not null, created_at timestamptz not null default now());
create table public.activity_logs (id uuid primary key default gen_random_uuid(), actor_id uuid references public.profiles, action text not null, entity_type text not null, entity_id uuid, metadata jsonb not null default '{}', created_at timestamptz not null default now());
create table public.email_templates (id uuid primary key default gen_random_uuid(), template_key text unique not null, subject text not null, html text not null, updated_at timestamptz not null default now());
create table public.business_settings (key text primary key, value jsonb not null, updated_at timestamptz not null default now());
create table public.roles (id uuid primary key default gen_random_uuid(), name text unique not null); create table public.permissions (id uuid primary key default gen_random_uuid(), key text unique not null); create table public.staff (id uuid primary key default gen_random_uuid(), profile_id uuid unique not null references public.profiles, branch_id uuid references public.branches, created_at timestamptz not null default now());
create index bookings_hall_slot_idx on public.bookings(hall_id,slot_start,slot_end) where status in ('pending_payment','confirmed'); create index bookings_customer_idx on public.bookings(customer_id,created_at desc); create index notifications_user_idx on public.notifications(user_id,created_at desc);
alter table public.bookings add constraint no_overlapping_hall_bookings exclude using gist (hall_id with =, tstzrange(slot_start,slot_end,'[)') with &&) where (status in ('pending_payment','confirmed'));
create or replace function public.is_admin() returns boolean language sql stable security definer set search_path=public as $$select exists(select 1 from profiles where id=auth.uid() and role in ('admin','super_admin'))$$;
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$begin insert into public.profiles(id,full_name) values(new.id,coalesce(new.raw_user_meta_data->>'full_name','')); return new; end;$$;
create trigger on_auth_user_created after insert on auth.users for each row execute function public.handle_new_user();
alter table public.profiles enable row level security; alter table public.bookings enable row level security; alter table public.booking_items enable row level security; alter table public.payments enable row level security; alter table public.notifications enable row level security; alter table public.reviews enable row level security;
create policy "profiles own read" on public.profiles for select using(id=auth.uid() or public.is_admin()); create policy "profiles own update" on public.profiles for update using(id=auth.uid()) with check(id=auth.uid());
create policy "bookings own read" on public.bookings for select using(customer_id=auth.uid() or public.is_admin()); create policy "bookings own create" on public.bookings for insert with check(customer_id=auth.uid()); create policy "bookings staff manage" on public.bookings for all using(public.is_admin()) with check(public.is_admin());
create policy "items through booking" on public.booking_items for select using(exists(select 1 from bookings b where b.id=booking_id and (b.customer_id=auth.uid() or public.is_admin()))); create policy "payments through booking" on public.payments for select using(exists(select 1 from bookings b where b.id=booking_id and (b.customer_id=auth.uid() or public.is_admin()))); create policy "notifications own" on public.notifications for select using(user_id=auth.uid()); create policy "review own or public" on public.reviews for select using(is_published or customer_id=auth.uid() or public.is_admin());
grant select on public.cities,public.branches,public.halls,public.hall_media,public.experiences,public.packages,public.package_items,public.addons,public.gallery,public.coupons to anon,authenticated;
